export const ALL_ICON_IDS = ICON_CATEGORIES.flatMap(c => c.icons);

export function searchIcons(query: string): { categoryId: string; iconId: string }[] {
  const q = query.toLowerCase().trim();
  const results: { categoryId: string; iconId: string }[] = [];
  for (const cat of ICON_CATEGORIES) {
    for (const icon of cat.icons) {
      if (icon.toLowerCase().includes(q)) {
        results.push({ categoryId: cat.id, iconId: icon });
      }
    }
  }
  return results;
}
